answer_code:
using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        int n = int.Parse(Console.ReadLine());
        var total = new Dictionary<string, int>();
        var order = new List<string>();
        for (int i = 0; i < n; i++) {
            var p = Console.ReadLine().Split();
            string name = p[0]; int sc = int.Parse(p[1]);
            if (!total.ContainsKey(name)) { total[name] = 0; order.Add(name); }
            total[name] += sc;
        }
        string best = null; int bestv = int.MinValue;
        foreach (var name in order) if (total[name] > bestv) { bestv = total[name]; best = name; }
        Console.WriteLine(best);
    }
}
